We can change the ans accordingly to clockwise or anti-clockwise.

import java.util.*;

class Solution {
    public List<Integer> boundaryClockwise(TreeNode root) {
        List<Integer> res = new ArrayList<>();
        if (root == null) return res;

        if (!isLeaf(root)) res.add(root.val);

        addRightBoundary(root.right, res);   // top -> bottom (exclude leaves)
        addLeavesRightToLeft(root, res);     // all leaves in R -> L order
        addLeftBoundaryReverse(root.left, res); // bottom -> top (exclude leaves)

        return res;
    }

    private boolean isLeaf(TreeNode node) {
        return node != null && node.left == null && node.right == null;
    }

    // right boundary: prefer right, else left
    private void addRightBoundary(TreeNode node, List<Integer> res) {
        while (node != null) {
            if (!isLeaf(node)) res.add(node.val);
            node = (node.right != null) ? node.right : node.left;
        }
    }

    // leaves in Right -> Left order
    private void addLeavesRightToLeft(TreeNode node, List<Integer> res) {
        if (node == null) return;
        if (isLeaf(node)) {
            res.add(node.val);
            return;
        }
        addLeavesRightToLeft(node.right, res);
        addLeavesRightToLeft(node.left, res);
    }

    // left boundary collected then reversed to make bottom -> top
    private void addLeftBoundaryReverse(TreeNode node, List<Integer> res) {
        List<Integer> tmp = new ArrayList<>();
        while (node != null) {
            if (!isLeaf(node)) tmp.add(node.val);
            node = (node.left != null) ? node.left : node.right;
        }
        for (int i = tmp.size() - 1; i >= 0; i--) res.add(tmp.get(i));
    }
}
